package org.eclipse.rdf4j.query.algebra.evaluation.impl.evaluationsteps;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.atomic.AtomicInteger;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryEvaluationStep;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class MinusQueryEvaluationStepTest {
	@Test
	void materializedRightOverflowFallsBackWithoutLeftRowCorrelation() {
		String previousLimit = System.setProperty(MinusQueryEvaluationStep.MAX_MATERIALIZED_RIGHT_ROWS_PROPERTY, "1");
		try {
			Value tenant = SimpleValueFactory.getInstance().createIRI("urn:tenant");
			Value matched = SimpleValueFactory.getInstance().createIRI("urn:matched");
			Value missed = SimpleValueFactory.getInstance().createIRI("urn:missed");
			QueryBindingSet parent = new QueryBindingSet(EmptyBindingSet.getInstance());
			parent.addBinding("tenant", tenant);
			List<BindingSet> leftRows = List.of(row("tenant", tenant, "x", matched),
					row("tenant", tenant, "x", missed));
			List<BindingSet> rightRows = List.of(row("tenant", tenant, "x", matched),
					row("tenant", tenant, "x", SimpleValueFactory.getInstance().createIRI("urn:other")));
			AtomicInteger rightEvaluations = new AtomicInteger();
			AtomicInteger rightEvaluationsWithLeftBinding = new AtomicInteger();
			QueryEvaluationStep left = ignored -> new CloseableIteratorIteration<>(leftRows.iterator());
			QueryEvaluationStep right = bindings -> {
				rightEvaluations.incrementAndGet();
				if (bindings.getValue("x") != null) {
					rightEvaluationsWithLeftBinding.incrementAndGet();
				}
				assertThat(bindings.getValue("tenant")).isEqualTo(tenant);
				return new CloseableIteratorIteration<>(rightRows.iterator());
			};

			MinusQueryEvaluationStep step = new MinusQueryEvaluationStep(left, right);

			List<BindingSet> result;
			try (CloseableIteration<BindingSet> iteration = step.evaluate(parent)) {
				result = drain(iteration);
			}
			assertThat(result).extracting(row -> row.getValue("x")).containsExactly(missed);
			assertThat(rightEvaluations).hasValueGreaterThan(1);
			assertThat(rightEvaluationsWithLeftBinding).hasValue(0);
		} finally {
			if (previousLimit == null) {
				System.clearProperty(MinusQueryEvaluationStep.MAX_MATERIALIZED_RIGHT_ROWS_PROPERTY);
			} else {
				System.setProperty(MinusQueryEvaluationStep.MAX_MATERIALIZED_RIGHT_ROWS_PROPERTY, previousLimit);
			}
		}
	}

	private static QueryBindingSet row(String name1, Value value1, String name2, Value value2) {
		QueryBindingSet bindings = new QueryBindingSet();
		bindings.addBinding(name1, value1);
		bindings.addBinding(name2, value2);
		return bindings;
	}

	private static List<BindingSet> drain(CloseableIteration<BindingSet> iteration) {
		List<BindingSet> result = new ArrayList<>();
		while (iteration.hasNext()) {
			result.add(iteration.next());
		}
		return result;
	}
}
